const body = $input.first().json;
let extracted = body.extracted;
if (typeof extracted === 'string') {
  try { extracted = JSON.parse(extracted); } catch(e) { extracted = {}; }
}

const now = new Date();
const proposalNo = `SR-${now.getFullYear()}${String(now.getMonth()+1).padStart(2,'0')}${String(now.getDate()).padStart(2,'0')}-${String(now.getHours()).padStart(2,'0')}${String(now.getMinutes()).padStart(2,'0')}`;

const fmt = (n) => {
  if (!n) return 'TBD';
  if (n >= 1_000_000_000) return `Rp ${(n/1_000_000_000).toFixed(1)} M`;
  if (n >= 1_000_000) return `Rp ${Math.round(n/1_000_000)} jt`;
  return new Intl.NumberFormat('id-ID',{style:'currency',currency:'IDR',minimumFractionDigits:0}).format(n);
};

const fmtFull = (n) => {
  if (!n) return 'TBD';
  return new Intl.NumberFormat('id-ID',{style:'currency',currency:'IDR',minimumFractionDigits:0}).format(n);
};

const rabAvg = body.rabAvg || 0;
const feeAvg = body.feeAvg || (rabAvg * 0.07);
const ppn = feeAvg * 0.11;
const totalFee = feeAvg + ppn;
const dp30 = totalFee * 0.30;
const prog40 = totalFee * 0.40;
const final30 = totalFee * 0.30;

const buildingType = extracted.building_type || body.buildingType || 'Bangunan';
const tier = extracted.tier || body.tier || 'Standar';
const area = extracted.area_sqm || body.areaSqm || 100;
const serviceType = extracted.service_type || body.serviceCategory || 'Arsitektur';

return [{
  json: {
    from: body.from,
    clientName: body.clientName || 'Bapak/Ibu',
    phoneNumberId: body.phoneNumberId,
    proposalNo,
    buildingType, tier, area, serviceType,
    rabAvg, rabFmt: fmt(rabAvg),
    feeAvg, feeFmt: fmt(feeAvg), feeFmtFull: fmtFull(feeAvg),
    ppn, ppnFmt: fmt(ppn), ppnFmtFull: fmtFull(ppn),
    totalFee, totalFeeFmt: fmt(totalFee), totalFeeFmtFull: fmtFull(totalFee),
    dp30Fmt: fmtFull(dp30),
    prog40Fmt: fmtFull(prog40),
    final30Fmt: fmtFull(final30),
    dateFormatted: now.toLocaleDateString('id-ID',{day:'numeric',month:'long',year:'numeric'}),
    validUntil: new Date(now.getTime() + 14*24*60*60*1000).toLocaleDateString('id-ID',{day:'numeric',month:'long',year:'numeric'})
  }
}];

// Build HTML proposal yang akan di-convert ke PDF via Carbone atau html-pdf
const d = $json;

const html = `<!DOCTYPE html>
<html lang="id">
<head>
<meta charset="UTF-8">
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body { font-family: 'Arial', sans-serif; font-size: 13px; color: #1a1a1a; }
  .page { padding: 48px; max-width: 800px; margin: 0 auto; }
  /* Header */
  .header { display: flex; justify-content: space-between; align-items: flex-start; padding-bottom: 24px; border-bottom: 3px solid #1a1a1a; margin-bottom: 32px; }
  .brand h1 { font-size: 24px; font-weight: 900; letter-spacing: -0.5px; }
  .brand p { font-size: 12px; color: #666; margin-top: 2px; }
  .proposal-info { text-align: right; }
  .proposal-info .no { font-size: 11px; color: #666; }
  .proposal-info .date { font-size: 12px; margin-top: 4px; }
  /* Title */
  .title-section { margin-bottom: 32px; }
  .title-section h2 { font-size: 20px; font-weight: 700; margin-bottom: 8px; }
  .title-section p { color: #555; font-size: 13px; }
  /* Client box */
  .client-box { background: #f5f5f5; border-left: 4px solid #1a1a1a; padding: 16px 20px; margin-bottom: 32px; border-radius: 0 4px 4px 0; }
  .client-box .label { font-size: 10px; text-transform: uppercase; letter-spacing: 0.8px; color: #888; margin-bottom: 4px; }
  .client-box .value { font-size: 14px; font-weight: 600; }
  /* Section */
  .section { margin-bottom: 28px; }
  .section-title { font-size: 11px; text-transform: uppercase; letter-spacing: 0.8px; color: #888; margin-bottom: 12px; padding-bottom: 8px; border-bottom: 1px solid #e0e0e0; }
  /* Table */
  table { width: 100%; border-collapse: collapse; }
  th { background: #1a1a1a; color: white; padding: 10px 12px; text-align: left; font-size: 11px; text-transform: uppercase; letter-spacing: 0.5px; }
  td { padding: 10px 12px; border-bottom: 1px solid #eee; font-size: 13px; }
  tr:last-child td { border-bottom: none; }
  .td-right { text-align: right; font-family: monospace; }
  .row-total td { background: #f5f5f5; font-weight: 700; border-top: 2px solid #1a1a1a; }
  .row-grand td { background: #1a1a1a; color: white; font-weight: 700; font-size: 14px; }
  /* Payment */
  .payment-grid { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 12px; }
  .payment-item { background: #f5f5f5; padding: 16px; border-radius: 4px; text-align: center; }
  .payment-item .pct { font-size: 24px; font-weight: 900; }
  .payment-item .label { font-size: 11px; color: #666; margin: 4px 0; }
  .payment-item .amount { font-size: 12px; font-weight: 600; font-family: monospace; }
  /* Timeline */
  .timeline { display: flex; flex-direction: column; gap: 8px; }
  .tl-item { display: flex; gap: 16px; align-items: flex-start; }
  .tl-dot { width: 8px; height: 8px; border-radius: 50%; background: #1a1a1a; margin-top: 5px; flex-shrink: 0; }
  .tl-content { font-size: 13px; }
  .tl-content strong { font-weight: 600; }
  /* Terms */
  .terms-list { list-style: none; display: flex; flex-direction: column; gap: 6px; }
  .terms-list li { padding-left: 16px; position: relative; font-size: 12px; color: #444; }
  .terms-list li::before { content: '—'; position: absolute; left: 0; color: #999; }
  /* Footer */
  .footer { margin-top: 48px; padding-top: 24px; border-top: 1px solid #e0e0e0; display: flex; justify-content: space-between; align-items: flex-end; }
  .signature { text-align: center; }
  .sig-line { width: 160px; border-bottom: 1px solid #1a1a1a; margin: 40px auto 8px; }
  .sig-label { font-size: 12px; color: #666; }
  .validity { font-size: 11px; color: #999; text-align: right; }
  .highlight { background: #f0f0f0; padding: 2px 6px; border-radius: 2px; font-family: monospace; font-size: 12px; }
</style>
</head>
<body>
<div class="page">

  <!-- Header -->
  <div class="header">
    <div class="brand">
      <h1>Sudut Ruang</h1>
      <p>Jasa Desain Arsitektur & Interior</p>
    </div>
    <div class="proposal-info">
      <div class="no">No. Proposal</div>
      <div class="date"><strong class="highlight">${d.proposalNo}</strong></div>
      <div class="date" style="margin-top:6px;color:#666">${d.dateFormatted}</div>
    </div>
  </div>

  <!-- Title -->
  <div class="title-section">
    <h2>Proposal Jasa Desain ${d.buildingType}</h2>
    <p>Estimasi biaya dan lingkup pekerjaan jasa desain ${d.serviceType.toLowerCase()} — ${d.tier}</p>
  </div>

  <!-- Client Info -->
  <div class="client-box">
    <div class="label">Dipersiapkan untuk</div>
    <div class="value">${d.clientName}</div>
  </div>

  <!-- Project Scope -->
  <div class="section">
    <div class="section-title">Lingkup Proyek</div>
    <table>
      <tr><th>Item</th><th>Detail</th></tr>
      <tr><td>Tipe Bangunan</td><td>${d.buildingType} — ${d.tier}</td></tr>
      <tr><td>Luas Area</td><td>${d.area} m²</td></tr>
      <tr><td>Jenis Jasa</td><td>Desain ${d.serviceType}</td></tr>
      <tr><td>Estimasi RAB Konstruksi</td><td class="td-right">${d.rabFmt}</td></tr>
    </table>
  </div>

  <!-- Fee Breakdown -->
  <div class="section">
    <div class="section-title">Rincian Biaya Jasa Desain</div>
    <table>
      <tr><th>Komponen</th><th style="text-align:right">Jumlah</th></tr>
      <tr><td>Fee Jasa Desain</td><td class="td-right">${d.feeFmtFull}</td></tr>
      <tr><td>PPN 11%</td><td class="td-right">${d.ppnFmtFull}</td></tr>
      <tr class="row-grand"><td>Total Tagihan</td><td class="td-right">${d.totalFeeFmtFull}</td></tr>
    </table>
    <p style="margin-top:10px;font-size:11px;color:#888">* Biaya konstruksi (RAB) merupakan tanggung jawab owner/client terpisah dari fee jasa desain.</p>
  </div>

  <!-- Payment Terms -->
  <div class="section">
    <div class="section-title">Termin Pembayaran</div>
    <div class="payment-grid">
      <div class="payment-item">
        <div class="pct">30%</div>
        <div class="label">Down Payment</div>
        <div class="amount">${d.dp30Fmt}</div>
        <div style="font-size:11px;color:#999;margin-top:4px">Saat kontrak ditandatangani</div>
      </div>
      <div class="payment-item">
        <div class="pct">40%</div>
        <div class="label">Progress Payment</div>
        <div class="amount">${d.prog40Fmt}</div>
        <div style="font-size:11px;color:#999;margin-top:4px">Saat gambar desain selesai</div>
      </div>
      <div class="payment-item">
        <div class="pct">30%</div>
        <div class="label">Final Payment</div>
        <div class="amount">${d.final30Fmt}</div>
        <div style="font-size:11px;color:#999;margin-top:4px">Saat semua dokumen diserahkan</div>
      </div>
    </div>
  </div>

  <!-- Timeline -->
  <div class="section">
    <div class="section-title">Estimasi Timeline</div>
    <div class="timeline">
      <div class="tl-item"><div class="tl-dot"></div><div class="tl-content"><strong>Minggu 1–2:</strong> Konsultasi, pengukuran, dan brief desain</div></div>
      <div class="tl-item"><div class="tl-dot"></div><div class="tl-content"><strong>Minggu 3–4:</strong> Konsep desain & presentasi awal</div></div>
      <div class="tl-item"><div class="tl-dot"></div><div class="tl-content"><strong>Minggu 5–6:</strong> Revisi dan finalisasi desain</div></div>
      <div class="tl-item"><div class="tl-dot"></div><div class="tl-content"><strong>Minggu 7–8:</strong> Penyerahan dokumen lengkap (gambar kerja + RAB detail)</div></div>
    </div>
  </div>

  <!-- Terms & Conditions -->
  <div class="section">
    <div class="section-title">Ketentuan Umum</div>
    <ul class="terms-list">
      <li>Proposal ini berlaku sampai dengan ${d.validUntil}.</li>
      <li>Harga sewaktu-waktu dapat berubah mengikuti kondisi pasar material.</li>
      <li>Biaya revisi di luar lingkup yang disepakati akan dikenakan biaya tambahan.</li>
      <li>Hak cipta desain sepenuhnya milik Sudut Ruang sampai pelunasan lunas.</li>
      <li>Estimasi RAB bersifat indikatif; RAB final dihitung setelah desain disetujui.</li>
      <li>Perubahan lingkup pekerjaan harus disepakati secara tertulis oleh kedua pihak.</li>
    </ul>
  </div>

  <!-- Signature -->
  <div class="footer">
    <div class="signature">
      <div class="sig-line"></div>
      <div class="sig-label">Sudut Ruang</div>
      <div style="font-size:11px;color:#999;margin-top:2px">Principal Architect</div>
    </div>
    <div class="signature">
      <div class="sig-line"></div>
      <div class="sig-label">${d.clientName}</div>
      <div style="font-size:11px;color:#999;margin-top:2px">Client</div>
    </div>
    <div class="validity">
      <div>Proposal No. ${d.proposalNo}</div>
      <div style="margin-top:4px">Berlaku s/d ${d.validUntil}</div>
    </div>
  </div>

</div>
</body>
</html>`;

return [{ json: { ...$json, htmlContent: html } }];

// Coba pakai hasil Carbone dulu, fallback ke html2pdf
// Di production, pilih salah satu dan disable yang lain

const carboneResult = $('Carbone — Render PDF').first()?.json;
const html2pdfResult = $('HTML2PDF — Generate PDF').first()?.binary?.pdfFile;

// Determine PDF source
let pdfReady = false;
let pdfBinary = null;
let pdfUrl = null;

if (html2pdfResult) {
  pdfBinary = html2pdfResult;
  pdfReady = true;
}

// Log untuk debugging
console.log('PDF ready:', pdfReady);

return [{
  json: {
    ...$('Prepare Proposal Data').first().json,
    pdfReady,
    pdfUrl
  },
  binary: pdfBinary ? { pdfFile: pdfBinary } : undefined
}];

